export const MODE_ORDER=['offseason','inseason','office','onice'];
export const TOTAL_WEEKS=32;
export const blockForWeek=(w)=>Math.ceil(w/4);
export const phaseForWeek=(w)=>(w<=8?'Off-Season':'In-Season');
export function resolveBlock(mode,week){
  const [lo,hi]=mode.range; let b=blockForWeek(Math.min(Math.max(week,lo),hi));
  if(!mode.blocks[b]){const keys=Object.keys(mode.blocks).map(Number).sort((a,z)=>a-z);
    b=keys.reduce((best,k)=>Math.abs(k-blockForWeek(week))<Math.abs(best-blockForWeek(week))?k:best,keys[0]);}
  return {block:b,content:mode.blocks[b],inRange:week>=lo&&week<=hi};
}
